from flask import Flask, request, jsonify
import jwt
from datetime import datetime, timedelta
from functools import wraps

app = Flask(__name__)
app.config['SECRET_KEY'] = 'sizin_gizli_anahtarınız_kimsenin_bilmemesi_gerekir'

def jwt_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = None
        if 'Authorization' in request.headers:
            auth_header = request.headers['Authorization']
            try:
                token = auth_header.split(" ")[1]
            except IndexError:
                return jsonify({'message': 'Token eksik veya hatalı formatta!'}), 401

        if not token:
            return jsonify({'message': 'Token gerekli!'}), 401

        try:
            data = jwt.decode(token, app.config['SECRET_KEY'], algorithms=["HS256"])
            request.current_user = data
        except jwt.ExpiredSignatureError:
            return jsonify({'message': 'Token süresi dolmuş!'}), 401
        except jwt.InvalidTokenError:
            return jsonify({'message': 'Geçersiz token!'}), 401
        except Exception as e:
            return jsonify({'message': f'Token işlenirken hata oluştu: {str(e)}'}), 401

        return f(*args, **kwargs)
    return decorated

@app.route('/login', methods=['POST'])
def login():
    auth = request.json
    if not auth or not auth.get('username') or not auth.get('password'):
        return jsonify({'message': 'Kullanıcı adı veya şifre eksik'}), 401

    if auth.get('username') == 'test' and auth.get('password') == 'test':
        token = jwt.encode({
            'user_id': 1,
            'username': auth.get('username'),
            'exp': datetime.utcnow() + timedelta(minutes=1)
        }, app.config['SECRET_KEY'], algorithm="HS256")
        return jsonify({'token': token})

    return jsonify({'message': 'Geçersiz kimlik bilgileri!'}), 401

@app.route('/protected', methods=['GET'])
@jwt_required
def protected_route():
    return jsonify({'message': f'Merhaba {request.current_user.get("username")}, tokeniniz geçerli!'})

@app.route('/')
def index():
    return jsonify({'message': 'JWT örnek API\'sine hoş geldiniz. Token almak için /login adresini, token kullanmak için /protected adresini deneyin.'})

if __name__ == '__main__':
    app.run(debug=True)
